class TileProcessorv4(nn.Module):
    """
    ONNX opset 12 compatible PyTorch module for splitting images into overlapping tiles.
    Uses vectorized operations for better performance while maintaining opset 12 compatibility.
    """
    def __init__(self, tile_size=256, overlap=32):
        super().__init__()
        self.tile_size = tile_size
        self.overlap = overlap
        self.stride = tile_size - overlap
        
    def forward(self, x):
        """
        Split input tensor into overlapping tiles using vectorized ONNX opset 12 compatible operations.
        
        Args:
            x: Input tensor [B, C, H, W]
            
        Returns:
            tiles: Tensor of tiles [N, C, tile_size, tile_size]
            positions: List of (row, col, start_h, start_w) for each tile
        """
        B, C, H, W = x.shape
        
        # Calculate number of tiles needed using basic operations
        num_tiles_h = (H - self.overlap + self.stride - 1) // self.stride
        num_tiles_w = (W - self.overlap + self.stride - 1) // self.stride
        
        # Calculate required padding
        padded_h = num_tiles_h * self.stride + self.overlap
        padded_w = num_tiles_w * self.stride + self.overlap
        
        # Calculate padding amounts
        pad_h = max(0, padded_h - H)
        pad_w = max(0, padded_w - W)
        
        # Apply padding if needed
        if pad_h > 0 or pad_w > 0:
            x = F.pad(x, (0, pad_w, 0, pad_h), mode='reflect')
        
        # Vectorized tile extraction using advanced indexing (opset 12 compatible)
        # Create coordinate grids for all tiles at once
        
        # Generate all starting positions
        h_starts = torch.arange(0, num_tiles_h, device=x.device) * self.stride
        w_starts = torch.arange(0, num_tiles_w, device=x.device) * self.stride
        
        # Create meshgrid for all tile positions
        h_grid, w_grid = torch.meshgrid(h_starts, w_starts, indexing='ij')
        h_grid = h_grid.flatten()  # [num_tiles_h * num_tiles_w]
        w_grid = w_grid.flatten()  # [num_tiles_h * num_tiles_w]
        
        # Create offset grids for tile coordinates
        tile_h_coords = torch.arange(self.tile_size, device=x.device).unsqueeze(1).expand(self.tile_size, self.tile_size)
        tile_w_coords = torch.arange(self.tile_size, device=x.device).unsqueeze(0).expand(self.tile_size, self.tile_size)
        
        # Vectorized tile extraction
        tiles = []
        for i in range(len(h_grid)):
            h_start = h_grid[i]
            w_start = w_grid[i]
            
            # Calculate absolute coordinates for this tile
            abs_h_coords = h_start + tile_h_coords
            abs_w_coords = w_start + tile_w_coords
            
            # Extract tile using advanced indexing (opset 12 compatible)
            tile = x[:, :, abs_h_coords, abs_w_coords]
            tiles.append(tile)
        
        # Stack all tiles
        tiles = torch.stack(tiles, dim=0)  # [N, B, C, tile_size, tile_size]
        tiles = tiles.squeeze(1)  # Remove batch dimension: [N, C, tile_size, tile_size]
        
        # Generate positions
        positions = []
        for i in range(num_tiles_h):
            for j in range(num_tiles_w):
                start_h = i * self.stride
                start_w = j * self.stride
                positions.append((i, j, start_h, start_w))
        
        return tiles, positions

