class TileMergerv4(nn.Module):
    """
    ONNX opset 12 compatible module for merging overlapping binary mask tiles.
    Uses only basic operations supported in opset 12.
    """
    def __init__(self, merge_strategy='confidence_weighted', confidence_threshold=0.5):
        super().__init__()
        self.merge_strategy = merge_strategy  # 'majority_vote', 'confidence_weighted', 'adaptive'
        self.confidence_threshold = confidence_threshold
        
    def _create_distance_weight_mask_opset12(self, tile_size, device):
        """Create distance-based weight mask using only opset 12 compatible operations."""
        # Create coordinate grids without indexing parameter (opset 12 compatible)
        y_coords = torch.arange(tile_size, device=device, dtype=torch.float32)
        x_coords = torch.arange(tile_size, device=device, dtype=torch.float32)
        
        # Manual meshgrid creation (opset 12 compatible)
        y = y_coords.unsqueeze(1).expand(tile_size, tile_size)
        x = x_coords.unsqueeze(0).expand(tile_size, tile_size)
        
        # Calculate distance from center using basic operations
        center = tile_size / 2.0 - 0.5
        dx = x - center
        dy = y - center
        
        # Distance calculation using basic ops
        dist_squared = dx * dx + dy * dy
        dist_from_center = torch.sqrt(dist_squared + 1e-8)  # Add epsilon for numerical stability
        
        # Maximum distance (corner to center)
        max_dist = torch.sqrt(torch.tensor(2.0 * center * center, device=device))
        
        # Convert to weight (higher at center, lower at edges)
        weight = 1.0 - (dist_from_center / max_dist)
        weight = torch.clamp(weight, 0.1, 1.0)  # Minimum weight to avoid zero weights
        
        return weight
        
    def _majority_vote_merge_opset12(self, tiles, positions, original_h, original_w):
        """ONNX opset 12 compatible majority voting merge."""
        device = tiles.device
        N, C, tile_size, _ = tiles.shape
        
        # Calculate padded dimensions using basic operations
        max_h = original_h
        max_w = original_w
        for pos in positions:
            max_h = max(max_h, pos[2] + tile_size)
            max_w = max(max_w, pos[3] + tile_size)
        
        # Initialize vote accumulators
        vote_sum = torch.zeros(1, C, max_h, max_w, device=device, dtype=torch.float32)
        vote_count = torch.zeros(1, 1, max_h, max_w, device=device, dtype=torch.float32)
        
        # Threshold tiles to binary using basic comparison
        binary_tiles = (tiles > self.confidence_threshold).float()
        
        # Accumulate votes using basic indexing
        for i in range(len(positions)):
            row, col, start_h, start_w = positions[i]
            end_h = start_h + tile_size
            end_w = start_w + tile_size
            
            # Add vote using basic tensor operations
            vote_sum[:, :, start_h:end_h, start_w:end_w] = (
                vote_sum[:, :, start_h:end_h, start_w:end_w] + binary_tiles[i:i+1]
            )
            vote_count[:, :, start_h:end_h, start_w:end_w] = (
                vote_count[:, :, start_h:end_h, start_w:end_w] + 1.0
            )
        
        # Majority vote using basic operations
        vote_count = torch.clamp(vote_count, min=1.0)  # Avoid division by zero
        vote_ratio = vote_sum / vote_count
        majority_mask = (vote_ratio > 0.5).float()
        
        # Crop to original dimensions using basic slicing
        result = majority_mask[:, :, :original_h, :original_w]
        return result
        
    def _confidence_weighted_merge_opset12(self, tiles, positions, original_h, original_w):
        """ONNX opset 12 compatible confidence-weighted merge."""
        device = tiles.device
        N, C, tile_size, _ = tiles.shape
        
        # Calculate padded dimensions
        max_h = original_h
        max_w = original_w
        for pos in positions:
            max_h = max(max_h, pos[2] + tile_size)
            max_w = max(max_w, pos[3] + tile_size)
        
        # Initialize accumulators
        weighted_sum = torch.zeros(1, C, max_h, max_w, device=device, dtype=torch.float32)
        weight_sum = torch.zeros(1, 1, max_h, max_w, device=device, dtype=torch.float32)
        
        # Create distance-based weight mask
        distance_weight = self._create_distance_weight_mask_opset12(tile_size, device)
        
        # Accumulate weighted predictions
        for i in range(len(positions)):
            row, col, start_h, start_w = positions[i]
            end_h = start_h + tile_size
            end_w = start_w + tile_size
            
            tile = tiles[i:i+1]
            
            # Calculate confidence weight using basic operations
            tile_centered = tile - 0.5
            confidence = torch.abs(tile_centered) * 2.0  # Range [0, 1]
            
            # Combine distance and confidence weights using basic operations
            distance_expanded = distance_weight.unsqueeze(0).unsqueeze(0)
            confidence_factor = 0.5 + confidence
            combined_weight = distance_expanded * confidence_factor
            
            # Accumulate using basic operations
            weighted_sum[:, :, start_h:end_h, start_w:end_w] = (
                weighted_sum[:, :, start_h:end_h, start_w:end_w] + tile * combined_weight
            )
            weight_sum[:, :, start_h:end_h, start_w:end_w] = (
                weight_sum[:, :, start_h:end_h, start_w:end_w] + combined_weight
            )
        
        # Normalize using basic operations
        weight_sum = torch.clamp(weight_sum, min=1e-8)
        merged = weighted_sum / weight_sum
        
        # Apply threshold to get binary mask
        binary_result = (merged > self.confidence_threshold).float()
        
        # Crop to original dimensions
        result = binary_result[:, :, :original_h, :original_w]
        return result
        
    def _adaptive_merge_opset12(self, tiles, positions, original_h, original_w):
        """ONNX opset 12 compatible adaptive merge."""
        device = tiles.device
        N, C, tile_size, _ = tiles.shape
        
        # Get both results using opset 12 compatible methods
        majority_result = self._majority_vote_merge_opset12(tiles, positions, original_h, original_w)
        confidence_result = self._confidence_weighted_merge_opset12(tiles, positions, original_h, original_w)
        
        # Calculate average confidence map
        max_h = original_h
        max_w = original_w
        for pos in positions:
            max_h = max(max_h, pos[2] + tile_size)
            max_w = max(max_w, pos[3] + tile_size)
        
        confidence_map = torch.zeros(1, C, max_h, max_w, device=device, dtype=torch.float32)
        count_map = torch.zeros(1, 1, max_h, max_w, device=device, dtype=torch.float32)
        
        # Calculate average confidence for each pixel
        for i in range(len(positions)):
            row, col, start_h, start_w = positions[i]
            end_h = start_h + tile_size
            end_w = start_w + tile_size
            
            tile = tiles[i:i+1]
            tile_centered = tile - 0.5
            tile_confidence = torch.abs(tile_centered) * 2.0
            
            confidence_map[:, :, start_h:end_h, start_w:end_w] = (
                confidence_map[:, :, start_h:end_h, start_w:end_w] + tile_confidence
            )
            count_map[:, :, start_h:end_h, start_w:end_w] = (
                count_map[:, :, start_h:end_h, start_w:end_w] + 1.0
            )
        
        count_map = torch.clamp(count_map, min=1.0)
        avg_confidence = confidence_map / count_map
        avg_confidence = avg_confidence[:, :, :original_h, :original_w]
        
        # Use majority vote for high-confidence regions, weighted for low-confidence
        high_confidence_mask = (avg_confidence > 0.7).float()
        low_confidence_mask = 1.0 - high_confidence_mask
        
        # Blend results using basic operations
        result = (high_confidence_mask * majority_result + 
                 low_confidence_mask * confidence_result)
        
        return result
        
    def _morphological_postprocess_opset12(self, mask, kernel_size=3):
        """ONNX opset 12 compatible morphological operations using max/min pooling."""
        # Opening (erosion followed by dilation) using basic pooling operations
        # Erosion approximation using negative max pooling
        padding = kernel_size // 2
        
        # Erosion: min pooling (implemented as negative max pooling)
        mask_neg = -mask
        eroded_neg = F.max_pool2d(mask_neg, kernel_size=kernel_size, stride=1, padding=padding)
        eroded = -eroded_neg
        
        # Dilation: max pooling
        opened = F.max_pool2d(eroded, kernel_size=kernel_size, stride=1, padding=padding)
        
        # Closing (dilation followed by erosion)
        # Dilation: max pooling
        dilated = F.max_pool2d(opened, kernel_size=kernel_size, stride=1, padding=padding)
        
        # Erosion: min pooling (implemented as negative max pooling)
        dilated_neg = -dilated
        closed_neg = F.max_pool2d(dilated_neg, kernel_size=kernel_size, stride=1, padding=padding)
        closed = -closed_neg
        
        return closed
        
    def forward(self, tiles, positions, original_h, original_w, apply_postprocessing=True):
        """
        ONNX opset 12 compatible binary mask merging.
        
        Args:
            tiles: Tensor of prediction tiles [N, C, tile_size, tile_size] (values in [0,1])
            positions: List of (row, col, start_h, start_w) for each tile
            original_h: Original image height
            original_w: Original image width
            apply_postprocessing: Whether to apply morphological post-processing
            
        Returns:
            merged: Binary mask [1, C, original_h, original_w]
        """
        if tiles.shape[0] == 0:
            return torch.zeros(1, tiles.shape[1], original_h, original_w, 
                             device=tiles.device, dtype=tiles.dtype)
        
        # Choose merging strategy using opset 12 compatible methods
        if self.merge_strategy == 'majority_vote':
            merged = self._majority_vote_merge_opset12(tiles, positions, original_h, original_w)
        elif self.merge_strategy == 'confidence_weighted':
            merged = self._confidence_weighted_merge_opset12(tiles, positions, original_h, original_w)
        elif self.merge_strategy == 'adaptive':
            merged = self._adaptive_merge_opset12(tiles, positions, original_h, original_w)
        else:
            # Default to confidence_weighted if unknown strategy
            merged = self._confidence_weighted_merge_opset12(tiles, positions, original_h, original_w)
        
        # Apply morphological post-processing using opset 12 compatible operations
        if apply_postprocessing:
            merged = self._morphological_postprocess_opset12(merged, kernel_size=3)
        
        return merged

