def plot_tiles(tiles, positions):
    """Plot all tiles in a grid layout"""
    n_tiles = tiles.shape[0]
    n_cols = int(np.ceil(np.sqrt(n_tiles)))
    n_rows = int(np.ceil(n_tiles / n_cols))
    
    fig, axes = plt.subplots(n_rows, n_cols, figsize=(15, 15))
    axes = axes.flatten()
    
    for i in range(n_tiles):
        axes[i].imshow(tiles[i,0].cpu(), cmap='gray')
        axes[i].set_title(f'Tile {i}')
        axes[i].axis('off')
    
    # Hide empty subplots
    for i in range(n_tiles, len(axes)):
        axes[i].axis('off')
        axes[i].set_visible(False)
    
    plt.tight_layout()
    plt.show()



