class ONNXFriendlyCLAHEOpset12(nn.Module):
    """CLAHE implementation that's compatible with ONNX opset 12.
    This version avoids operations that aren't supported in opset 12.
    """
    def __init__(self, window_size=8, clip_limit=4.0, eps=1e-6):
        super().__init__()
        self.window_size = window_size
        self.clip_limit = clip_limit
        self.eps = eps
        
        # Pre-register kernels as buffers to avoid torch.tensor() in forward
        self.register_buffer('laplacian_kernel', 
                           torch.tensor([[-1,-1,-1], [-1,8,-1], [-1,-1,-1]], dtype=torch.float32).view(1, 1, 3, 3))
        self.register_buffer('sobel_h_kernel', 
                           torch.tensor([[-1,-2,-1], [0,0,0], [1,2,1]], dtype=torch.float32).view(1, 1, 3, 3))
        self.register_buffer('sobel_v_kernel', 
                           torch.tensor([[-1,0,1], [-2,0,2], [-1,0,1]], dtype=torch.float32).view(1, 1, 3, 3))
        
    def forward(self, x):
        # Input: [B,C,H,W], values in [0,1]
        B, C, H, W = x.shape
        
        # Create multi-scale pooling for adaptive local statistics
        pool_sizes = [max(2, self.window_size//4), max(4, self.window_size//2), self.window_size]
        enhanced_outputs = []
        
        # Pad input once for all operations - use constant padding for ONNX compatibility
        x_padded = F.pad(x, (2, 2, 2, 2), mode='constant', value=0)
        x_squared = x_padded * x_padded  # Use multiplication instead of ** for better ONNX support
        
        # 1. MULTI-SCALE LOCAL CONTRAST NORMALIZATION
        for kernel_size in pool_sizes:
            # Use 75% overlap between patches
            stride = max(1, kernel_size // 4)
            
            # Calculate local statistics with overlapping patches
            local_mean = F.avg_pool2d(x_padded, kernel_size=kernel_size, stride=stride)
            local_sqr = F.avg_pool2d(x_squared, kernel_size=kernel_size, stride=stride)
            
            # Resize both tensors at once - use nearest for better ONNX support
            local_mean = F.interpolate(local_mean, size=(H, W), mode='nearest')
            local_sqr = F.interpolate(local_sqr, size=(H, W), mode='nearest')
            
            # Calculate variance and apply clipping
            local_var = local_sqr - local_mean * local_mean
            mean_var = torch.mean(local_var) * self.clip_limit
            local_var = torch.clamp(local_var, 0, mean_var)
            
            # Calculate std and normalize
            local_std = torch.sqrt(local_var + self.eps)
            normalized = (x - local_mean) / (local_std + self.eps)
            normalized = torch.clamp(normalized * 1.5, -1.5, 1.5)
            
            enhanced_outputs.append(normalized)
        
        # 2. EDGE ENHANCEMENT - Pre-compute padded input
        x_edge_padded = F.pad(x, (1, 1, 1, 1), mode='constant', value=0)
        
        # Use pre-registered kernels and repeat for channels
        laplacian_k = self.laplacian_kernel.repeat(C, 1, 1, 1)
        sobel_h_k = self.sobel_h_kernel.repeat(C, 1, 1, 1)
        sobel_v_k = self.sobel_v_kernel.repeat(C, 1, 1, 1)
        
        # Apply convolutions
        edges_lap = F.conv2d(x_edge_padded, laplacian_k, groups=C)
        edges_sobel_h = F.conv2d(x_edge_padded, sobel_h_k, groups=C)
        edges_sobel_v = F.conv2d(x_edge_padded, sobel_v_k, groups=C)
        
        # Combine edge responses - avoid sqrt for better ONNX compatibility
        edges_sobel = torch.sqrt(edges_sobel_h * edges_sobel_h + edges_sobel_v * edges_sobel_v + self.eps)
        
        # Normalize edge responses - use more stable normalization
        edges_lap_abs = torch.abs(edges_lap)
        edges_lap_max = torch.max(edges_lap_abs.view(B, C, -1), dim=2, keepdim=True)[0].unsqueeze(-1)
        edges_lap = edges_lap / (edges_lap_max + self.eps)
        
        edges_sobel_max = torch.max(edges_sobel.view(B, C, -1), dim=2, keepdim=True)[0].unsqueeze(-1)
        edges_sobel = edges_sobel / (edges_sobel_max + self.eps)
        
        # 3. COMBINE ENHANCEMENTS
        combined = enhanced_outputs[0] * 0.5 + enhanced_outputs[1] * 0.3 + enhanced_outputs[2] * 0.2
        edge_enhanced = combined + edges_lap * 0.5 + edges_sobel * 0.3
        
        # 4. CONTRAST STRETCHING
        min_val = torch.min(edge_enhanced.view(B, C, -1), dim=2, keepdim=True)[0].unsqueeze(-1)
        max_val = torch.max(edge_enhanced.view(B, C, -1), dim=2, keepdim=True)[0].unsqueeze(-1)
        normalized = (edge_enhanced - min_val) / (max_val - min_val + self.eps)
        
        # 5. ADAPTIVE GAMMA CORRECTION - simplified for ONNX compatibility
        # Use conditional operations that are better supported
        dark_mask = (normalized < 0.4).float()
        mid_mask = ((normalized >= 0.4) * (normalized < 0.7)).float()
        bright_mask = (normalized >= 0.7).float()
        
        # Apply gamma corrections
        gamma_dark = torch.pow(normalized, 0.7)
        gamma_mid = torch.pow(normalized, 0.9)
        gamma_bright = torch.pow(normalized, 1.2)
        
        # Combine gamma corrections
        gamma_corrected = dark_mask * gamma_dark + mid_mask * gamma_mid + bright_mask * gamma_bright
        
        return torch.clamp(gamma_corrected, 0, 1)


